export const sameArray = (a1: any[], a2: any[]): boolean => {
  if (!Array.isArray(a1) || !Array.isArray(a2) || a1.length !== a2.length) {
    return false;
  }

  // Conta frequência de cada elemento
  const freq1 = new Map();
  const freq2 = new Map();

  for (const item of a1) {
    freq1.set(item, (freq1.get(item) || 0) + 1);
  }

  for (const item of a2) {
    freq2.set(item, (freq2.get(item) || 0) + 1);
  }

  // Compara mapas de frequência
  if (freq1.size !== freq2.size) return false;

  for (const [key, value] of freq1) {
    if (freq2.get(key) !== value) {
      return false;
    }
  }

  return true;
};

export const uniqueBy = <T>(array: T[], key: keyof T): T[] => {
  const seen = new Set();
  return array.filter(item => {
    const value = item[key];
    if (seen.has(value)) return false;
    seen.add(value);
    return true;
  });
}

export const uniqueListBy = (arr: any[], key: string): any[] => {
  return [...new Map(arr.map(item => [item[key], item])).values()];
};

export const base64toFile = (
  base64: string,
  filename: string
): File => {
  const ARR = base64.split(',');
  // const MIME = (ARR[0].match(/:(.*?);/)[1]) || undefined;
  let mime: string = '';
  if (ARR && ARR.length) {
    mime = ((ARR[0].match(/:(.*?);/) || [])[1]) || '';
  } // if
  const BSTR = atob(ARR[1]);
  let n = BSTR.length;
  const U8ARR = new Uint8Array(n);
  while (n--) {
    U8ARR[n] = BSTR.charCodeAt(n);
  } // while
  return new File([U8ARR], filename, { type: mime });
};

export const blobToFile = (
  blob: Blob,
  fileName: string
): File => {
  const B: any = blob;
  B.lastModifiedDate = new Date();
  B.name = fileName;

  //Cast to a File() type
  // return <File>blob;
  return <any>blob;
};

export const breakFone = (val: string) => {
  const VAL = !!val ? val.toString().trim().replace(/^\+|-|\(|\)/g, '') : '';
  // console.log(val);

  const RET: ICorFoneInfoRet = {
    country: '',
    ddd: '',
    number: '',
    n1: '',
    n2: '',
    cellphone: VAL.length % 2 !== 0,
  };

  switch (VAL.length) {
    case 8:
      RET.country = '';
      RET.ddd = '';
      RET.number = VAL;
      RET.n1 = VAL.slice(0, 4);
      RET.n2 = VAL.slice(4);
      break;

    case 9:
      RET.country = '';
      RET.ddd = '';
      RET.number = VAL;
      RET.n1 = VAL.slice(0, 5);
      RET.n2 = VAL.slice(5);
      break;

    case 10:
      RET.country = '';
      RET.ddd = VAL.slice(0, 2);
      RET.number = VAL.slice(2);
      RET.n1 = VAL.slice(2, 6);
      RET.n2 = VAL.slice(6);
      break;

    case 11:
      RET.country = '';
      RET.ddd = VAL.slice(0, 2);
      RET.number = VAL.slice(2);
      RET.n1 = VAL.slice(2, 7);
      RET.n2 = VAL.slice(7);
      break;

    case 12:
      RET.country = VAL.slice(0, 2);
      RET.ddd = VAL.slice(2, 4);
      RET.number = VAL.slice(4);
      RET.n1 = VAL.slice(4, 8);
      RET.n2 = VAL.slice(8);
      break;

    case 13:
      RET.country = VAL.slice(0, 2);
      RET.ddd = VAL.slice(2, 4);
      RET.number = VAL.slice(4);
      RET.n1 = VAL.slice(4, 9);
      RET.n2 = VAL.slice(9);
      break;

    default:
      return null;
  } // switch

  // console.log(RET);
  return RET;
};

